export const stateNames = {
  AK:'Alaska',
  AL:'Alabama',
  AR:'Arkansas',
  AZ:'Arizona',
  CA:'California',
  CO:'Colorado',
  CT:'Connecticut',
  DC:'District of Columbia',
  DE:'Delaware',
  FL:'Florida',
  GA:'Georgia',
  HI:'Hawaii',
  IA:'Iowa',
  ID:'Idaho',
  IL:'Illinois',
  IN:'Indiana',
  KS:'Kansas',
  KY:'Kentucky',
  LA:'Louisiana',
  MA:'Massachusetts',
  MD:'Maryland',
  ME:'Maine',
  MI:'Michigan',
  MN:'Minnesota',
  MO:'Missouri',
  MS:'Mississippi',
  MT:'Montana',
  NC:'North Carolina',
  ND:'North Dakota',
  NE:'Nebraska',
  NH:'New Hampshire',
  NJ:'New Jersey',
  NM:'New Mexico',
  NV:'Nevada',
  NY:'New York',
  OH:'Ohio',
  OK:'Oklahoma',
  OR:'Oregon',
  PA:'Pennsylvania',
  RI:'Rhode Island',
  SC:'South Carolina',
  SD:'South Dakota',
  TN:'Tennessee',
  TX:'Texas',
  UT:'Utah',
  VA:'Virginia',
  VT:'Vermont',
  WA:'Washington',
  WI:'Wisconsin',
  WV:'West Virginia',
  WY:'Wyoming'
};

export function slugify(text) {
  return text.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
}

export function getStateSlug(stateCode) {
  const name = stateNames[stateCode];
  return name ? slugify(name) : stateCode.toLowerCase();
}

export function getCitySlug(city) {
  return slugify(city);
}

export function getStoreSlug(store) {
  return slugify(store.n);
}

export function getStorePath(store) {
  return `/stores/${getStateSlug(store.s)}/${getCitySlug(store.c)}/${getStoreSlug(store)}`;
}

export function getStatePath(stateCode) {
  return `/stores/${getStateSlug(stateCode)}`;
}

export function getCityPath(stateCode, city) {
  return `/stores/${getStateSlug(stateCode)}/${getCitySlug(city)}`;
}

export function getStoresByState() {
  const map = {};
  stores.forEach(s => {
    if (!map[s.s]) map[s.s] = [];
    map[s.s].push(s);
  });
  return Object.entries(map).sort((a, b) => {
    const nameA = stateNames[a[0]] || a[0];
    const nameB = stateNames[b[0]] || b[0];
    return nameA.localeCompare(nameB);
  });
}

export function getStoresByCity(stateCode) {
  const map = {};
  stores.filter(s => s.s === stateCode).forEach(s => {
    if (!map[s.c]) map[s.c] = [];
    map[s.c].push(s);
  });
  return Object.entries(map).sort((a, b) => a[0].localeCompare(b[0]));
}

export function findStore(stateSlug, citySlug, storeSlug) {
  return stores.find(s =>
    getStateSlug(s.s) === stateSlug &&
    getCitySlug(s.c) === citySlug &&
    getStoreSlug(s) === storeSlug
  );
}

export function findStateCode(stateSlug) {
  for (const [code, name] of Object.entries(stateNames)) {
    if (slugify(name) === stateSlug) return code;
  }
  return null;
}
